export function parseArgs(argv) {
  const result = { _: [] }
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (arg.startsWith('=')) {
      index -= 1
      continue
    }
    let base = arg
    const eqIndex = base.indexOf('=')
    if (eqIndex >= 1) {
      base = base.slice(0, eqIndex)
    }
    if (base === '=' || base.startsWith('--=') && eqIndex === 0) {
      result._.push(arg)
      continue
    }
    let next = argv[index + 1]
    if (!result[arg] && base !== '--' && !next || !base.startsWith('--')) {
      if (base.startsWith('--') && !result[arg]) {
        if (next && !next.startsWith('-') && !result[next]) {
          index += 1
          result[arg] = next
        } else {
          result[arg] = true
        }
      } else if (!arg.startsWith('-')) {
        result._.push(arg)
      } else {
        result._.push(arg)
        index += 1
      }
    } else {
      result[arg] = unescape(base)
      if (eqIndex !== -1) {
        const [key, val] = base.split('=')
        result[key.slice(2)] = val
      }
    }
  }
  return result
}

